"use client"

import * as React from "react"
import {
  QueryClient,
  QueryClientProvider,
  useQueries,
  type UseQueryResult,
} from "@tanstack/react-query"

import type { DatoolQueryDefinition } from "./types"

type DatoolContextValue = {
  defaultQueryId: string
  queryDefinitions: Record<string, DatoolQueryDefinition<any, any, any>>
  queryResults: Record<string, UseQueryResult<unknown>>
  resetView: (queryId: string) => void
  viewRevisionByQueryId: Record<string, number>
}

export type DatoolQueryValue<
  TData = unknown,
  TFilters = unknown,
  TRow extends Record<string, unknown> = Record<string, unknown>,
> = {
  definition: DatoolQueryDefinition<TData, TFilters, TRow>
  id: string
  resetView: () => void
  result: UseQueryResult<TData>
  rows: TRow[]
  viewRevision: number
}

export type DatoolProviderProps = {
  children: React.ReactNode
  defaultQuery?: string
  queries: Record<string, DatoolQueryDefinition<any, any, any>>
  queryClient?: QueryClient
}

const DatoolContext = React.createContext<DatoolContextValue | null>(null)

export function DatoolProvider({
  children,
  defaultQuery,
  queries,
  queryClient: providedQueryClient,
}: DatoolProviderProps) {
  const queryClient = React.useMemo(
    () => providedQueryClient ?? new QueryClient(),
    [providedQueryClient]
  )

  return (
    <QueryClientProvider client={queryClient}>
      <DatoolProviderInner defaultQuery={defaultQuery} queries={queries}>
        {children}
      </DatoolProviderInner>
    </QueryClientProvider>
  )
}

function DatoolProviderInner({
  children,
  defaultQuery,
  queries,
}: Required<Pick<DatoolProviderProps, "children" | "queries">> & {
  defaultQuery?: string
}) {
  const queryEntries = React.useMemo(() => Object.entries(queries), [queries])

  if (queryEntries.length === 0) {
    throw new Error("DatoolProvider requires at least one query definition.")
  }

  const resolvedDefaultQuery = React.useMemo(() => {
    if (defaultQuery) {
      if (!queries[defaultQuery]) {
        throw new Error(`Unknown default datool query "${defaultQuery}".`)
      }

      return defaultQuery
    }

    if (queryEntries.length === 1) {
      return queryEntries[0]![0]
    }

    throw new Error(
      "DatoolProvider requires a defaultQuery when more than one query is registered."
    )
  }, [defaultQuery, queries, queryEntries])

  const queryResults = useQueries({
    queries: queryEntries.map(([, definition]) => {
      const options = definition.getQueryOptions(definition.filters)

      return {
        ...options,
        refetchInterval:
          definition.pollingIntervalMs === undefined
            ? options.refetchInterval
            : definition.pollingIntervalMs,
      }
    }),
  })

  const [viewRevisionByQueryId, setViewRevisionByQueryId] = React.useState<
    Record<string, number>
  >({})

  const resetView = React.useCallback((queryId: string) => {
    setViewRevisionByQueryId((current) => ({
      ...current,
      [queryId]: (current[queryId] ?? 0) + 1,
    }))
  }, [])

  const value = React.useMemo(
    () => ({
      defaultQueryId: resolvedDefaultQuery,
      queryDefinitions: queries,
      queryResults: Object.fromEntries(
        queryEntries.map(([queryId], index) => [queryId, queryResults[index]])
      ),
      resetView,
      viewRevisionByQueryId,
    }),
    [
      queries,
      queryEntries,
      queryResults,
      resetView,
      resolvedDefaultQuery,
      viewRevisionByQueryId,
    ]
  )

  return <DatoolContext.Provider value={value}>{children}</DatoolContext.Provider>
}

export function useDatool() {
  const context = React.useContext(DatoolContext)

  if (!context) {
    throw new Error("useDatool must be used inside DatoolProvider.")
  }

  return context
}

export function useDatoolQuery<
  TData = unknown,
  TFilters = unknown,
  TRow extends Record<string, unknown> = Record<string, unknown>,
>(queryId?: string) {
  const context = useDatool()
  const resolvedQueryId = queryId ?? context.defaultQueryId
  const definition = context.queryDefinitions[resolvedQueryId] as
    | DatoolQueryDefinition<TData, TFilters, TRow>
    | undefined
  const result = context.queryResults[resolvedQueryId] as
    | UseQueryResult<TData>
    | undefined

  if (!definition || !result) {
    throw new Error(`Unknown datool query "${resolvedQueryId}".`)
  }

  const rows =
    definition.kind === "collection"
      ? definition.getRows(result.data)
      : ([] as TRow[])

  return React.useMemo(
    () =>
      ({
        definition,
        id: resolvedQueryId,
        resetView: () => context.resetView(resolvedQueryId),
        result,
        rows,
        viewRevision: context.viewRevisionByQueryId[resolvedQueryId] ?? 0,
      }) satisfies DatoolQueryValue<TData, TFilters, TRow>,
    [context, definition, resolvedQueryId, result, rows]
  )
}

export function useDatoolCollectionQuery<
  TData = unknown,
  TFilters = unknown,
  TRow extends Record<string, unknown> = Record<string, unknown>,
>(queryId?: string) {
  const query = useDatoolQuery<TData, TFilters, TRow>(queryId)

  if (query.definition.kind !== "collection") {
    throw new Error(
      `Datool query "${query.id}" is not a collection query and cannot be used here.`
    )
  }

  return query as DatoolQueryValue<TData, TFilters, TRow> & {
    definition: Extract<
      DatoolQueryDefinition<TData, TFilters, TRow>,
      { kind: "collection" }
    >
  }
}

"use client"

import * as React from "react"

import {
  DataTable,
  DataTableProvider,
  type DataTableColumnConfig,
  type DataTableRowAction,
  type DataTableRowActionContext,
} from "@/components/data-table"

import { useDatoolCollectionQuery } from "./provider"
import type { DatoolQueryActionContext } from "./types"

export type DatoolDataTableProps<
  TRow extends Record<string, unknown> = Record<string, unknown>,
> = {
  columns: DataTableColumnConfig<TRow>[]
  query?: string
  rowClassName?: (row: TRow) => string | undefined
  rowHeight?: number
  rowStyle?: (row: TRow) => React.CSSProperties | undefined
}

function toActionContext<TData, TFilters, TRow extends Record<string, unknown>>({
  collection,
  context,
}: {
  collection: ReturnType<typeof useDatoolCollectionQuery<TData, TFilters, TRow>>
  context: DataTableRowActionContext<TRow>
}) {
  return {
    actionRowIds: context.actionRowIds,
    actionRows: context.actionRows,
    anchorRow: context.anchorRow ?? null,
    anchorRowId: context.anchorRowId ?? null,
    filters: collection.definition.filters,
    queryId: collection.id,
    refetch: collection.result.refetch,
    result: collection.result,
    rows: collection.rows,
    selectedRowIds: context.selectedRowIds,
    selectedRows: context.selectedRows,
    setFilters: collection.definition.setFilters,
  } satisfies DatoolQueryActionContext<TData, TFilters, TRow>
}

export function DatoolDataTable<
  TData = unknown,
  TFilters = unknown,
  TRow extends Record<string, unknown> = Record<string, unknown>,
>({
  columns,
  query,
  rowClassName,
  rowHeight = 48,
  rowStyle,
}: DatoolDataTableProps<TRow>) {
  const collection = useDatoolCollectionQuery<TData, TFilters, TRow>(query)
  const rowActions = React.useMemo<DataTableRowAction<TRow>[]>(
    () => {
      const actions = collection.definition.actions ?? []

      return actions.map((action, index) => {
        const disabled = action.disabled
        const hidden = action.hidden
        const label = action.label

        return {
          button: action.button,
          disabled:
            typeof disabled === "function"
              ? (context: DataTableRowActionContext<TRow>) =>
                  disabled(
                    toActionContext({
                      collection,
                      context,
                    })
                  )
              : disabled,
          hidden:
            typeof hidden === "function"
              ? (context: DataTableRowActionContext<TRow>) =>
                  hidden(
                    toActionContext({
                      collection,
                      context,
                    })
                  )
              : hidden,
          icon: action.icon,
          id: `query-action-${index}`,
          label:
            typeof label === "function"
              ? (context: DataTableRowActionContext<TRow>) =>
                  label(
                    toActionContext({
                      collection,
                      context,
                    })
                  )
              : label,
          onSelect: async (context: DataTableRowActionContext<TRow>) => {
            await action.onSelect(
              toActionContext({
                collection,
                context,
              })
            )
          },
          scope: action.scope,
          variant: action.variant,
        }
      })
    },
    [collection]
  )
  const enableRowSelection = React.useMemo(
    () => rowActions.some((action) => action.scope === "selection"),
    [rowActions]
  )

  return (
    <div className="min-h-0 flex-1">
      <DataTableProvider
        autoScrollToBottom
        columns={columns}
        data={collection.rows}
        enableRowSelection={enableRowSelection}
        getRowId={collection.definition.getRowId}
        id={`datool-demo-${collection.id}`}
        key={`${collection.id}:${collection.viewRevision}`}
        onSearchChange={collection.definition.search?.onChange}
        rowActions={rowActions}
        rowClassName={rowClassName}
        rowHeight={rowHeight}
        rowStyle={rowStyle}
        search={collection.definition.search?.value}
        statePersistence="none"
      >
        <DataTable />
      </DataTableProvider>
    </div>
  )
}

"use client"

import { RefreshCwIcon, SearchIcon, Trash2Icon } from "lucide-react"

import { Button } from "@/components/data-table/ui/button"

import { useDatoolCollectionQuery, useDatoolQuery } from "./provider"

export function SearchFilter({
  className,
  placeholder = "Search prompts...",
  query,
}: {
  className?: string
  placeholder?: string
  query?: string
}) {
  const datoolQuery = useDatoolCollectionQuery(query)
  const search = datoolQuery.definition.search

  if (!search) {
    return null
  }

  return (
    <label className={className ?? "search-shell"}>
      <SearchIcon className="size-4 text-muted-foreground" />
      <input
        className="search-input"
        onChange={(event) => {
          search.onChange(event.target.value)
        }}
        placeholder={placeholder}
        type="search"
        value={search.value}
      />
    </label>
  )
}

export function RefreshButton({
  className,
  label = "Refresh data",
  query,
}: {
  className?: string
  label?: string
  query?: string
}) {
  const datoolQuery = useDatoolQuery(query)

  return (
    <Button
      aria-label={label}
      className={className}
      onClick={() => void datoolQuery.result.refetch()}
      size="icon-xl"
      type="button"
      variant="outline"
    >
      <RefreshCwIcon className="size-4" />
    </Button>
  )
}

export function ClearButton({
  className,
  label = "Reset view",
  query,
}: {
  className?: string
  label?: string
  query?: string
}) {
  const datoolQuery = useDatoolQuery(query)
  const canReset =
    datoolQuery.definition.kind === "collection"
      ? Boolean(datoolQuery.definition.search) || datoolQuery.viewRevision > 0
      : datoolQuery.viewRevision > 0

  return (
    <Button
      aria-label={label}
      className={className}
      disabled={!canReset}
      onClick={() => {
        if (datoolQuery.definition.kind === "collection") {
          datoolQuery.definition.search?.reset()
        }
        datoolQuery.resetView()
      }}
      size="icon-xl"
      type="button"
      variant="outline"
    >
      <Trash2Icon className="size-4" />
    </Button>
  )
}

export function ErrorMessage({
  className = "rounded-2xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700",
  query,
}: {
  className?: string
  query?: string
}) {
  const datoolQuery = useDatoolQuery(query)
  const error = datoolQuery.result.error

  if (!error) {
    return null
  }

  return (
    <div className={className}>
      {error instanceof Error ? error.message : String(error)}
    </div>
  )
}
